import{_ as e,o as t,c as r,a2 as o}from"./chunks/framework.Cr-Z7ngm.js";const u=JSON.parse('{"title":"自动还款","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"transfers-and-fx/auto-repayment.md","filePath":"zh-CN/transfers-and-fx/auto-repayment.md"}'),l={name:"transfers-and-fx/auto-repayment.md"};function i(n,a,p,h,s,d){return t(),r("div",null,[...a[0]||(a[0]=[o('<h1 id="自动还款" tabindex="-1">自动还款 <a class="header-anchor" href="#自动还款" aria-label="Permalink to &quot;自动还款&quot;">​</a></h1><p>自动还款是一项系统自动货币兑换服务。当证券账户内有结算欠款，同时持有其他货币余额时，系统会自动兑换货币以减少欠款利息成本。</p><h2 id="开启-关闭" tabindex="-1">开启 / 关闭 <a class="header-anchor" href="#开启-关闭" aria-label="Permalink to &quot;开启 / 关闭&quot;">​</a></h2><p>路径：长桥 App - 我的 - 设置 - 账户设置 - 自动还款</p><p>2025 年 6 月后开户的客户默认关闭自动还款功能。</p><p>注意：未开通自动还款功能时，余额通将不再跨币种赎回。</p><h2 id="触发条件" tabindex="-1">触发条件 <a class="header-anchor" href="#触发条件" aria-label="Permalink to &quot;触发条件&quot;">​</a></h2><p>在香港工作日的 07:00 HKT 和 16:15 HKT，当开启了自动还款功能，且同时满足以下两个条件时将触发自动还款：</p><ol><li>证券账户中持有其他货币计价的可提资金余额 ≥ 100 港元（或等值货币）</li><li>证券账户内的已欠款资金 ≥ 100 港元（或等值货币）</li></ol><p>如在上述时间之前已自行在 App 内完成货币兑换，系统将不再进行自动转换。</p><h2 id="兑换汇率" tabindex="-1">兑换汇率 <a class="header-anchor" href="#兑换汇率" aria-label="Permalink to &quot;兑换汇率&quot;">​</a></h2><p>自动货币兑换采用截至 07:00 HKT 及 16:15 HKT 的系统汇率。兑换页面展示的汇率仅供参考，请以实际兑换后的金额为准。</p><h2 id="余额通自动赎回" tabindex="-1">余额通自动赎回 <a class="header-anchor" href="#余额通自动赎回" aria-label="Permalink to &quot;余额通自动赎回&quot;">​</a></h2><p>开通自动还款后，若同时持有余额通产品，当满足以下条件时系统会自动发起余额通赎回：</p><ol><li>持有的余额通产品价值 ≥ 100 港元（或等值货币）</li><li>证券账户中无任何可提资金，且已欠款资金 ≥ 100 港元（或等值货币）</li></ol><p>自动赎回金额不超过账户中的已欠款资金。赎回到账后，如符合自动还款条件，将自动进行货币兑换还款。</p><p>关闭自动还款功能时，余额通自动赎回服务也将同时关闭。</p><h2 id="查看记录" tabindex="-1">查看记录 <a class="header-anchor" href="#查看记录" aria-label="Permalink to &quot;查看记录&quot;">​</a></h2><p>长桥 App - 资产 - 全部功能 - 资金记录中查看换汇记录，也可通过当日结单查看货币兑换的具体详情。</p><h2 id="风险提示" tabindex="-1">风险提示 <a class="header-anchor" href="#风险提示" aria-label="Permalink to &quot;风险提示&quot;">​</a></h2><p>使用自动还款服务即同意接受货币兑换可能因汇率变动而产生的收益或亏损，客户应自行承担使用本服务可能产生的风险及损失，包括货币兑换成本及因汇率波动造成的亏损。</p>',21)])])}const f=e(l,[["render",i]]);export{u as __pageData,f as default};
